{
    "name": "差异菌分析",
    "moduleName": "abundance_difference",
    "script_type": "r",
    "image": "registry.cn-hangzhou.aliyuncs.com/wybioinfo/datascience-notebook:x86_64-ubuntu-22.04",
    "saveAnalysisMethod": "metaphlan_abundance_difference_matrix",
    "dbInputFiled":["control","treatment"],
    "formJson": [
        {
            "name": "group_field",
            "label": "分组列",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "type": "GroupFieldSelect"
        },
        {
            "name": "treatment",
            "label": "处理组",
            "db":true,
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "type": "GroupSelectSampleButton",
            "group": "group_field"
        },
        {
            "name": "control",
            "label": "对照组",
            "db":true,
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "type": "GroupSelectSampleButton",
            "group": "group_field"
        },
        {
            "name": "feature_type",
            "label": "选择特征列:",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "initialValue": "gene_name",
            "data": [
                {
                    "label": "gene name",
                    "value": "gene_name"
                },
                {
                    "label": "gene id",
                    "value": "gene_id"
                }
            ],
            "type": "BaseSelect"
        },{
            "name": "sig_type",
            "label": "选择显著性指标:",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "initialValue": "pvalue",
            "data": [
                {
                    "label": "pvalue",
                    "value": "pvalue"
                },
                {
                    "label": "padj",
                    "value": "padj"
                }
            ],
            "type": "BaseSelect"
        },{
            "name": "sig_thresh",
            "label": "显著性阈值:",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "min":0,
            "max":1,
            "initialValue": 0.05,
            "type": "BaseInputNumber"
        },{
            "name": "logfc_thresh",
            "label": "logfc阈值:",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "initialValue":1,
            "type": "BaseInputNumber"
        },
        {
            "name": "heatmap_gene_num",
            "label": "热图基因个数:",
            "rules": [
                {
                    "required": true,
                    "message": "该字段不能为空!"
                }
            ],
            "initialValue": 20,
            "type": "BaseInputNumber"
        }

    ]
}
